First, delete the default Class1.cs file. Then create these model files:

1. **Models/ConstructionSite.cs** - A construction site
```csharp
namespace SiteInspector.Shared.Models;

public class ConstructionSite
{
    public string Id { get; set; } = Guid.NewGuid().ToString();
    public string Name { get; set; } = string.Empty;
    public string Address { get; set; } = string.Empty;
    public string? Notes { get; set; }
    public DateTime CreatedAt { get; set; } = DateTime.UtcNow;
}
```

2. **Models/Inspection.cs** - An inspection visit to a site
```csharp
namespace SiteInspector.Shared.Models;

public class Inspection
{
    public string Id { get; set; } = Guid.NewGuid().ToString();
    public string SiteId { get; set; } = string.Empty;
    public string SiteName { get; set; } = string.Empty;
    public string InspectorName { get; set; } = string.Empty;
    public DateTime InspectedAt { get; set; } = DateTime.UtcNow;
    public string? Notes { get; set; }
    public InspectionStatus Status { get; set; } = InspectionStatus.InProgress;
    public List<ChecklistItem> ChecklistItems { get; set; } = new();
    public List<PhotoRecord> Photos { get; set; } = new();
    public SyncState SyncState { get; set; } = SyncState.Pending;
    public DateTime? LastSyncedAt { get; set; }
}

public enum InspectionStatus
{
    InProgress,
    Completed,
    NeedsFollowUp
}

public enum SyncState
{
    Pending,
    Synced,
    Failed
}
```

3. **Models/ChecklistItem.cs** - A checklist item within an inspection
```csharp
