            const getRequest = store.get(id);
            getRequest.onsuccess = () => {
                const record = getRequest.result;
                if (record) {
                    record.syncState = 1; // SyncState.Synced
                    record.lastSyncedAt = new Date().toISOString();
                    store.put(record);
