    savePhoto: async function (id, inspectionId, fileName, caption, takenAt, fileSizeBytes, base64Data) {
        const db = await this._openDb();

        // Convert base64 to Blob
        const byteCharacters = atob(base64Data);
        const byteNumbers = new Uint8Array(byteCharacters.length);
        for (let i = 0; i < byteCharacters.length; i++) {
            byteNumbers[i] = byteCharacters.charCodeAt(i);
        }
        const blob = new Blob([byteNumbers]);

        const record = {
            id: id,
            inspectionId: inspectionId,
            fileName: fileName,
            caption: caption,
            takenAt: takenAt,
            fileSizeBytes: fileSizeBytes,
            data: blob
        };

        return new Promise((resolve, reject) => {
            const tx = db.transaction("photos", "readwrite");
            tx.objectStore("photos").put(record);
            tx.oncomplete = () => resolve();
            tx.onerror = (e) => reject(e.target.error);
        });
    },

    _blobToBase64: function (blob) {
        return new Promise((resolve, reject) => {
            const reader = new FileReader();
            reader.onloadend = () => {
                // Remove data URL prefix (e.g. "data:application/octet-stream;base64,")
                const base64 = reader.result.split(",")[1];
                resolve(base64);
            };
            reader.onerror = reject;
            reader.readAsDataURL(blob);
        });
    },

    getPhoto: async function (id) {
        const db = await this._openDb();
        return new Promise((resolve, reject) => {
            const tx = db.transaction("photos", "readonly");
            const request = tx.objectStore("photos").get(id);
