                    fileName: record.fileName,
                    caption: record.caption,
                    takenAt: record.takenAt,
                    fileSizeBytes: record.fileSizeBytes,
                    data: base64
                });
            };
            request.onerror = (e) => reject(e.target.error);
        });
    },

