using Microsoft.JSInterop;
using SiteInspector.Shared.Models;

namespace SiteInspector.Client.Services;

public class IndexedDbService
{
    private readonly IJSRuntime _js;
    private bool _initialized;

    public IndexedDbService(IJSRuntime js) => _js = js;

    public async Task InitializeAsync()
    {
        if (!_initialized)
        {
            await _js.InvokeVoidAsync("indexedDb.initialize");
            _initialized = true;
        }
    }

    // Sites
    public async Task AddSiteAsync(ConstructionSite site)
    {
        await InitializeAsync();
        await _js.InvokeVoidAsync("indexedDb.addSite", site);
    }

    public async Task<List<ConstructionSite>> GetAllSitesAsync()
    {
        await InitializeAsync();
        return await _js.InvokeAsync<List<ConstructionSite>>("indexedDb.getAllSites") ?? new();
    }

    public async Task<ConstructionSite?> GetSiteAsync(string id)
    {
        await InitializeAsync();
        return await _js.InvokeAsync<ConstructionSite?>("indexedDb.getSite", id);
    }

    public async Task DeleteSiteAsync(string id)
    {
        await InitializeAsync();
        await _js.InvokeVoidAsync("indexedDb.deleteSite", id);
    }

    // Inspections
    public async Task SaveInspectionAsync(Inspection inspection)
    {
        await InitializeAsync();
        await _js.InvokeVoidAsync("indexedDb.addOrUpdateInspection", inspection);
    }

    public async Task<Inspection?> GetInspectionAsync(string id)
    {
        await InitializeAsync();
        return await _js.InvokeAsync<Inspection?>("indexedDb.getInspection", id);
    }

    public async Task<List<Inspection>> GetInspectionsBySiteAsync(string siteId)
    {
        await InitializeAsync();
        return await _js.InvokeAsync<List<Inspection>>("indexedDb.getInspectionsBySite", siteId) ?? new();
    }

    public async Task<List<Inspection>> GetAllInspectionsAsync()
    {
        await InitializeAsync();
        return await _js.InvokeAsync<List<Inspection>>("indexedDb.getAllInspections") ?? new();
    }

    public async Task DeleteInspectionAsync(string id)
    {
        await InitializeAsync();
        await _js.InvokeVoidAsync("indexedDb.deleteInspection", id);
    }

    public async Task<List<Inspection>> GetPendingInspectionsAsync()
    {
        await InitializeAsync();
        return await _js.InvokeAsync<List<Inspection>>("indexedDb.getPendingInspections") ?? new();
    }

    public async Task MarkSyncedAsync(string id)
    {
        await InitializeAsync();
        await _js.InvokeVoidAsync("indexedDb.markSynced", id);
    }

    // Photos
    public async Task SavePhotoAsync(string inspectionId, string fileName, string? caption, long fileSizeBytes, string base64Data)
    {
        await InitializeAsync();
        var id = Guid.NewGuid().ToString();
        await _js.InvokeVoidAsync("indexedDb.savePhoto", id, inspectionId, fileName, caption, DateTime.UtcNow.ToString("o"), fileSizeBytes, base64Data);
    }

    public async Task<List<PhotoRecord>> GetPhotosByInspectionAsync(string inspectionId)
    {
        await InitializeAsync();
        return await _js.InvokeAsync<List<PhotoRecord>>("indexedDb.getPhotosByInspection", inspectionId) ?? new();
    }

    public async Task<string?> GetPhotoDataAsync(string photoId)
    {
        await InitializeAsync();
        return await _js.InvokeAsync<string?>("indexedDb.getPhotoWithData", photoId);
    }

    public async Task DeletePhotoAsync(string id)
    {
        await InitializeAsync();
        await _js.InvokeVoidAsync("indexedDb.deletePhoto", id);
    }

    // Connectivity
    public async Task<bool> IsOnlineAsync()
    {
        return await _js.InvokeAsync<bool>("indexedDb.isOnline");
    }
}

using SiteInspector.Shared.Models;
using System.Net.Http.Json;

namespace SiteInspector.Client.Services;

public class SyncService : IDisposable
{
    private readonly IndexedDbService _db;
    private readonly HttpClient _http;
    private Timer? _timer;

    public event Action<SyncStatus>? OnSyncStatusChanged;
    public SyncStatus CurrentStatus { get; private set; } = new();

    public SyncService(IndexedDbService db, HttpClient http)
    {
        _db = db;
        _http = http;
    }

    public void StartAutoSync(TimeSpan interval)
    {
        _timer = new Timer(async _ => await TrySyncAsync(), null, TimeSpan.Zero, interval);
    }

    public async Task TrySyncAsync()
    {
        if (!await _db.IsOnlineAsync())
        {
            CurrentStatus = new SyncStatus { IsOnline = false, LastAttempt = DateTime.UtcNow };
            OnSyncStatusChanged?.Invoke(CurrentStatus);
            return;
        }

        CurrentStatus = new SyncStatus { IsOnline = true, IsSyncing = true, LastAttempt = DateTime.UtcNow };
        OnSyncStatusChanged?.Invoke(CurrentStatus);

        try
        {
            var pending = await _db.GetPendingInspectionsAsync();
            int synced = 0;
            int failed = 0;

            foreach (var inspection in pending)
            {
                try
                {
                    var response = await _http.PostAsJsonAsync("api/inspections", inspection);
                    if (response.IsSuccessStatusCode)
                    {
                        await _db.MarkSyncedAsync(inspection.Id);
                        synced++;
                    }
                    else
                    {
                        failed++;
                    }
                }
                catch
                {
                    failed++;
                }
            }

            CurrentStatus = new SyncStatus
            {
                IsOnline = true,
                IsSyncing = false,
                LastAttempt = DateTime.UtcNow,
                LastSuccess = failed == 0 ? DateTime.UtcNow : CurrentStatus.LastSuccess,
                PendingCount = failed,
                LastSyncedCount = synced
            };
        }
        catch
        {
            CurrentStatus = new SyncStatus
            {
                IsOnline = await _db.IsOnlineAsync(),
                IsSyncing = false,
                LastAttempt = DateTime.UtcNow,
                Error = "Sync failed"
            };
        }

        OnSyncStatusChanged?.Invoke(CurrentStatus);
    }

    public void Dispose() => _timer?.Dispose();
}

public class SyncStatus
{
    public bool IsOnline { get; set; }
    public bool IsSyncing { get; set; }
    public DateTime? LastAttempt { get; set; }
    public DateTime? LastSuccess { get; set; }
    public int PendingCount { get; set; }
    public int LastSyncedCount { get; set; }
    public string? Error { get; set; }
}

