        📍 Manage Sites
    </button>
</div>

@if (pendingCount > 0)
{
    <div class="pending-banner" @onclick="SyncNow">
        🔄 @pendingCount inspection(s) pending sync — tap to sync now
    </div>
}

<h2>Recent Inspections</h2>
@if (recentInspections.Any())
{
    <div class="card-list">
        @foreach (var inspection in recentInspections)
        {
            <div class="card" @onclick="() => ViewInspection(inspection.Id)">
                <div class="card-header">
                    <strong>@inspection.SiteName</strong>
                    <span class="badge @GetStatusClass(inspection.Status)">@inspection.Status</span>
                </div>
