                    <span>👷 @inspection.InspectorName</span>
                </div>
                <div class="card-footer">
                    <span class="sync-badge @GetSyncStateClass(inspection.SyncState)">
                        @GetSyncIcon(inspection.SyncState) @inspection.SyncState
                    </span>
