@code {
    [Parameter] public string? SiteId { get; set; }

    private List<ConstructionSite> sites = new();
    private string selectedSiteId = string.Empty;
    private string selectedSiteName = string.Empty;
    private string inspectorName = string.Empty;
    private string generalNotes = string.Empty;
    private InspectionStatus status = InspectionStatus.InProgress;
    private List<ChecklistItem> checklist = new();
    private HashSet<string> expandedNotes = new();
    private List<PhotoRecord> photoRecords = new();
    private List<(string id, string base64)> photoDataList = new();
    private bool isSaving;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            sites = await Db.GetAllSitesAsync();
            checklist = ChecklistTemplates.GetSafetyChecklist();

            if (!string.IsNullOrEmpty(SiteId))
            {
                selectedSiteId = SiteId;
                var site = await Db.GetSiteAsync(SiteId);
                selectedSiteName = site?.Name ?? "Unknown Site";
            }

            StateHasChanged();
        }
    }

    private void ToggleResult(ChecklistItem item, CheckResult result)
    {
        item.Result = item.Result == result ? CheckResult.NotChecked : result;
    }

    private async Task HandlePhotoSelected(InputFileChangeEventArgs e)
    {
        foreach (var file in e.GetMultipleFiles(10))
        {
            try
            {
                var buffer = new byte[file.Size];
                await file.OpenReadStream(maxAllowedSize: 10 * 1024 * 1024).ReadAsync(buffer);
                var base64 = Convert.ToBase64String(buffer);
                var id = Guid.NewGuid().ToString();
                var record = new PhotoRecord
                {
                    Id = id,
                    FileName = file.Name,
                    TakenAt = DateTime.UtcNow,
                    FileSizeBytes = file.Size
                };
                photoRecords.Add(record);
                photoDataList.Add((id, base64));
            }
            catch { /* skip files that are too large */ }
        }
    }

    private void RemovePhoto(PhotoRecord photo)
    {
        photoRecords.Remove(photo);
        photoDataList.RemoveAll(p => p.id == photo.Id);
    }

    private async Task SaveInspection()
    {
        var siteId = !string.IsNullOrEmpty(SiteId) ? SiteId : selectedSiteId;
        if (string.IsNullOrWhiteSpace(siteId) || string.IsNullOrWhiteSpace(inspectorName))
            return;

        isSaving = true;
        StateHasChanged();

        try
        {
            var site = await Db.GetSiteAsync(siteId);
            var inspection = new Inspection
            {
                SiteId = siteId,
                SiteName = site?.Name ?? "Unknown",
                InspectorName = inspectorName,
                Notes = generalNotes,
                Status = status,
                ChecklistItems = checklist,
                Photos = photoRecords,
                SyncState = SyncState.Pending
            };

            await Db.SaveInspectionAsync(inspection);

            // Save photo blobs
            foreach (var (id, base64) in photoDataList)
            {
                var record = photoRecords.First(p => p.Id == id);
                await Db.SavePhotoAsync(inspection.Id, record.FileName, record.Caption, record.FileSizeBytes, base64);
            }

            Nav.NavigateTo($"/inspection/{inspection.Id}");
        }
        finally
        {
            isSaving = false;
        }
    }

    private void GoBack() => Nav.NavigateTo("/");
}
```

