    @if (inspection.SyncState != SyncState.Synced)
    {
        <button class="btn-primary btn-large full-width" @onclick="TrySync">
            🔄 Sync Now
        </button>
    }
}
else if (loaded)
{
    <div class="empty-state">
        <p>Inspection not found.</p>
    </div>
}

@code {
    [Parameter] public string Id { get; set; } = string.Empty;

    private Inspection? inspection;
    private List<PhotoRecord> photos = new();
    private HashSet<string> expandedPhotos = new();
