@code {
    private List<Inspection> recentInspections = new();
    private int pendingCount;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            await LoadData();
            Sync.OnSyncStatusChanged += _ => InvokeAsync(async () => { await LoadData(); StateHasChanged(); });
            StateHasChanged();
        }
    }

    private async Task LoadData()
    {
        var all = await Db.GetAllInspectionsAsync();
        recentInspections = all.OrderByDescending(i => i.InspectedAt).Take(10).ToList();
        pendingCount = all.Count(i => i.SyncState != SyncState.Synced);
