        { IsOnline: true } => "pending",
        _ => "offline"
    };

    private string GetSyncText() => Sync.CurrentStatus switch
    {
        { IsSyncing: true } => "Syncing...",
        { IsOnline: true } when pendingCount == 0 => "Online",
        { IsOnline: true } => "Pending",
        _ => "Offline"
    };

    private string GetStatusClass(InspectionStatus status) => status switch
    {
        InspectionStatus.Completed => "badge-success",
        InspectionStatus.NeedsFollowUp => "badge-warning",
        _ => "badge-info"
    };

    private string GetSyncStateClass(SyncState state) => state switch
    {
        SyncState.Synced => "sync-ok",
        SyncState.Failed => "sync-fail",
        _ => "sync-pending"
    };

    private string GetSyncIcon(SyncState state) => state switch
    {
        SyncState.Synced => "☁️",
        SyncState.Failed => "⚠️",
        _ => "📱"
    };
}
