        <h3>✅ Checklist Results</h3>
        <div class="results-summary">
            <span class="result-count pass">✅ @inspection.ChecklistItems.Count(i => i.Result == CheckResult.Pass) Pass</span>
            <span class="result-count fail">❌ @inspection.ChecklistItems.Count(i => i.Result == CheckResult.Fail) Fail</span>
            <span class="result-count na">➖ @inspection.ChecklistItems.Count(i => i.Result == CheckResult.NotApplicable) N/A</span>
            <span class="result-count unchecked">⬜ @inspection.ChecklistItems.Count(i => i.Result == CheckResult.NotChecked) Unchecked</span>
        </div>

        @{
            string? currentCategory = null;
        }
        @foreach (var item in inspection.ChecklistItems.OrderBy(i => i.SortOrder))
        {
            if (item.Category != currentCategory)
            {
                currentCategory = item.Category;
                <h4 class="category-header">@currentCategory</h4>
            }
            <div class="result-item @GetResultClass(item.Result)">
                <span class="result-icon">@GetResultIcon(item.Result)</span>
                <span class="result-desc">@item.Description</span>
                @if (!string.IsNullOrEmpty(item.Notes))
                {
                    <div class="result-notes">📝 @item.Notes</div>
                }
            </div>
        }
    </div>

    @if (photos.Any())
    {
        <div class="card">
            <h3>📸 Photos (@photos.Count)</h3>
            <div class="photo-grid">
                @foreach (var photo in photos)
                {
                    <div class="photo-card" @onclick="() => TogglePhotoExpand(photo.Id)">
                        @if (expandedPhotos.Contains(photo.Id) && loadedPhotos.ContainsKey(photo.Id))
                        {
                            <img src="data:image/jpeg;base64,@loadedPhotos[photo.Id]" alt="@photo.FileName" class="photo-full" />
                        }
                        else
                        {
                            <div class="photo-placeholder">📷</div>
                        }
                        <div class="photo-info">
                            <span>@photo.FileName</span>
                            @if (!string.IsNullOrEmpty(photo.Caption))
                            {
                                <span class="text-muted">@photo.Caption</span>
                            }
                        </div>
                    </div>
                }
            </div>
        </div>
    }

    @if (inspection.SyncState != SyncState.Synced)
    {
        <button class="btn-primary btn-large full-width" @onclick="TrySync">
            🔄 Sync Now
        </button>
    }
}
else if (loaded)
{
    <div class="empty-state">
        <p>Inspection not found.</p>
    </div>
}

@code {
    [Parameter] public string Id { get; set; } = string.Empty;

    private Inspection? inspection;
    private List<PhotoRecord> photos = new();
    private HashSet<string> expandedPhotos = new();
    private Dictionary<string, string> loadedPhotos = new();
    private bool loaded;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            inspection = await Db.GetInspectionAsync(Id);
            if (inspection is not null)
            {
                photos = await Db.GetPhotosByInspectionAsync(Id);
            }
            loaded = true;
            StateHasChanged();
        }
    }

    private async Task TogglePhotoExpand(string photoId)
    {
        if (expandedPhotos.Contains(photoId))
        {
            expandedPhotos.Remove(photoId);
        }
        else
        {
            expandedPhotos.Add(photoId);
            if (!loadedPhotos.ContainsKey(photoId))
            {
                var data = await Db.GetPhotoDataAsync(photoId);
                if (data is not null)
                    loadedPhotos[photoId] = data;
            }
        }
    }

    private async Task TrySync() => await Sync.TrySyncAsync();

    private string GetStatusClass(InspectionStatus s) => s switch
    {
        InspectionStatus.Completed => "badge-success",
        InspectionStatus.NeedsFollowUp => "badge-warning",
        _ => "badge-info"
    };

    private string GetSyncClass(SyncState s) => s switch
    {
        SyncState.Synced => "sync-ok",
        SyncState.Failed => "sync-fail",
        _ => "sync-pending"
    };

    private string GetSyncIcon(SyncState s) => s switch
    {
        SyncState.Synced => "☁️",
        SyncState.Failed => "⚠️",
        _ => "📱"
    };

    private string GetResultClass(CheckResult r) => r switch
    {
        CheckResult.Pass => "result-pass",
        CheckResult.Fail => "result-fail",
        CheckResult.NotApplicable => "result-na",
        _ => "result-unchecked"
    };

    private string GetResultIcon(CheckResult r) => r switch
    {
        CheckResult.Pass => "✅",
        CheckResult.Fail => "❌",
        CheckResult.NotApplicable => "➖",
        _ => "⬜"
    };
}
