@page "/sites"
@using SiteInspector.Client.Services
@using SiteInspector.Shared.Models
@inject IndexedDbService Db
@inject NavigationManager Nav

<div class="page-header">
    <button class="btn-back" @onclick='() => Nav.NavigateTo("/")'>← Back</button>
    <h1>📍 Construction Sites</h1>
</div>

@if (showForm)
{
    <div class="card form-card">
        <h3>@(isEditing ? "Edit Site" : "Add New Site")</h3>
        <div class="form-group">
            <label>Site Name *</label>
            <input type="text" @bind="editSite.Name" placeholder="e.g. Riverside Tower" class="input-large" />
        </div>
        <div class="form-group">
            <label>Address *</label>
            <input type="text" @bind="editSite.Address" placeholder="123 Main St" class="input-large" />
        </div>
        <div class="form-group">
            <label>Notes</label>
            <textarea @bind="editSite.Notes" rows="3" placeholder="Optional notes..."></textarea>
        </div>
        <div class="form-actions">
            <button class="btn-primary" @onclick="SaveSite">💾 Save</button>
            <button class="btn-secondary" @onclick="CancelEdit">Cancel</button>
        </div>
    </div>
}
else
{
    <button class="btn-primary btn-large full-width" @onclick="ShowAddForm">➕ Add New Site</button>
}

<div class="card-list">
    @foreach (var site in sites)
    {
        <div class="card">
            <div class="card-header">
                <strong>@site.Name</strong>
            </div>
            <div class="card-body">
                <span>📍 @site.Address</span>
                @if (!string.IsNullOrEmpty(site.Notes))
                {
                    <span class="text-muted">@site.Notes</span>
                }
            </div>
            <div class="card-footer">
                <button class="btn-small btn-primary" @onclick="() => StartInspection(site)">🔍 Inspect</button>
                <button class="btn-small btn-secondary" @onclick="() => EditSite(site)">✏️</button>
                <button class="btn-small btn-danger" @onclick="() => DeleteSite(site)">🗑️</button>
            </div>
        </div>
    }
</div>

@if (!sites.Any() && !showForm)
{
    <div class="empty-state">
        <p>No sites added yet. Add your first construction site above.</p>
    </div>
}

@code {
    private List<ConstructionSite> sites = new();
    private ConstructionSite editSite = new();
    private bool showForm;
    private bool isEditing;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            sites = await Db.GetAllSitesAsync();
            StateHasChanged();
        }
    }

    private void ShowAddForm()
    {
        editSite = new ConstructionSite();
        isEditing = false;
        showForm = true;
    }

    private void EditSite(ConstructionSite site)
    {
        editSite = new ConstructionSite
        {
            Id = site.Id,
            Name = site.Name,
            Address = site.Address,
            Notes = site.Notes,
            CreatedAt = site.CreatedAt
        };
        isEditing = true;
        showForm = true;
    }

    private async Task SaveSite()
    {
        if (string.IsNullOrWhiteSpace(editSite.Name)) return;
        await Db.AddSiteAsync(editSite);
        sites = await Db.GetAllSitesAsync();
        showForm = false;
    }

    private void CancelEdit()
    {
        showForm = false;
    }

    private async Task DeleteSite(ConstructionSite site)
    {
        await Db.DeleteSiteAsync(site.Id);
        sites = await Db.GetAllSitesAsync();
    }

    private void StartInspection(ConstructionSite site)
    {
        Nav.NavigateTo($"/new-inspection/{site.Id}");
    }
}

