@code {
    private List<ConstructionSite> sites = new();
    private ConstructionSite editSite = new();
    private bool showForm;
    private bool isEditing;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            sites = await Db.GetAllSitesAsync();
            StateHasChanged();
        }
    }

    private void ShowAddForm()
    {
        editSite = new ConstructionSite();
        isEditing = false;
        showForm = true;
    }

    private void EditSite(ConstructionSite site)
    {
        editSite = new ConstructionSite
        {
            Id = site.Id,
            Name = site.Name,
            Address = site.Address,
            Notes = site.Notes,
            CreatedAt = site.CreatedAt
        };
        isEditing = true;
        showForm = true;
    }

    private async Task SaveSite()
    {
        if (string.IsNullOrWhiteSpace(editSite.Name)) return;
        await Db.AddSiteAsync(editSite);
        sites = await Db.GetAllSitesAsync();
        showForm = false;
    }

    private void CancelEdit()
    {
        showForm = false;
    }

    private async Task DeleteSite(ConstructionSite site)
    {
        await Db.DeleteSiteAsync(site.Id);
        sites = await Db.GetAllSitesAsync();
    }

    private void StartInspection(ConstructionSite site)
    {
        Nav.NavigateTo($"/new-inspection/{site.Id}");
    }
}

