+@page "/new-inspection"
+@page "/new-inspection/{SiteId}"
+@using SiteInspector.Client.Services
+@using SiteInspector.Shared.Models
+@inject IndexedDbService Db
+@inject NavigationManager Nav
+@inject IJSRuntime JS
+
+<div class="page-header">
+    <button class="btn-back" @onclick="GoBack">← Back</button>
+    <h1>🔍 New Inspection</h1>
+</div>
+
+<div class="inspection-form">
+    @if (string.IsNullOrEmpty(SiteId))
+    {
+        <div class="form-group">
+            <label>Select Site *</label>
+            <select @bind="selectedSiteId" class="input-large">
+                <option value="">-- Choose a site --</option>
+                @foreach (var site in sites)
+                {
+                    <option value="@site.Id">@site.Name — @site.Address</option>
+                }
+            </select>
+        </div>
+    }
+    else
+    {
+        <div class="site-banner">📍 @selectedSiteName</div>
+    }
+
+    <div class="form-group">
+        <label>Inspector Name *</label>
+        <input type="text" @bind="inspectorName" placeholder="Your name" class="input-large" />
+    </div>
+
+    <h2>Safety Checklist</h2>
+    @{
+        string? currentCategory = null;
+    }
+    @foreach (var item in checklist)
+    {
+        if (item.Category != currentCategory)
+        {
+            currentCategory = item.Category;
+            <h3 class="category-header">@currentCategory</h3>
+        }
+        <div class="checklist-item @(item.Result != CheckResult.NotChecked ? "checked" : "")">
+            <div class="checklist-description">@item.Description</div>
+            <div class="checklist-buttons">
+                <button class="check-btn pass @(item.Result == CheckResult.Pass ? "active" : "")"
+                        @onclick="() => ToggleResult(item, CheckResult.Pass)">✅</button>
+                <button class="check-btn fail @(item.Result == CheckResult.Fail ? "active" : "")"
+                        @onclick="() => ToggleResult(item, CheckResult.Fail)">❌</button>
+                <button class="check-btn na @(item.Result == CheckResult.NotApplicable ? "active" : "")"
+                        @onclick="() => ToggleResult(item, CheckResult.NotApplicable)">➖</button>
+            </div>
+            @if (expandedNotes.Contains(item.Id))
+            {
+                <textarea class="item-notes" @bind="item.Notes" placeholder="Add notes for this item..." rows="2"></textarea>
+            }
+            else
+            {
+                <button class="btn-link" @onclick="() => expandedNotes.Add(item.Id)">
+                    @(string.IsNullOrEmpty(item.Notes) ? "📝 Add note" : $"📝 {item.Notes[..Math.Min(item.Notes.Length, 30)]}...")
+                </button>
+            }
+        </div>
+    }
+
+    <h2>📸 Photos</h2>
+    <div class="photo-section">
+        <label class="photo-capture-btn">
+            📷 Take Photo / Choose File
+            <InputFile OnChange="HandlePhotoSelected" accept="image/*" capture="environment" multiple class="hidden-input" />
+        </label>
+        @if (photoRecords.Any())
+        {
+            <div class="photo-grid">
+                @foreach (var photo in photoRecords)
+                {
+                    <div class="photo-thumb">
+                        <div class="photo-name">@photo.FileName</div>
+                        <button class="btn-small btn-danger" @onclick="() => RemovePhoto(photo)">🗑️</button>
+                    </div>
+                }
+            </div>
+        }
+    </div>
+
+    <div class="form-group">
+        <label>General Notes</label>
+        <textarea @bind="generalNotes" rows="4" placeholder="Overall observations, concerns, follow-up items..." class="input-large"></textarea>
+    </div>
+
+    <div class="form-group">
+        <label>Status</label>
+        <div class="status-buttons">
+            <button class="status-btn @(status == InspectionStatus.InProgress ? "active" : "")"
+                    @onclick="() => status = InspectionStatus.InProgress">🔄 In Progress</button>
+            <button class="status-btn @(status == InspectionStatus.Completed ? "active" : "")"
+                    @onclick="() => status = InspectionStatus.Completed">✅ Completed</button>
+            <button class="status-btn @(status == InspectionStatus.NeedsFollowUp ? "active" : "")"
+                    @onclick="() => status = InspectionStatus.NeedsFollowUp">⚠️ Needs Follow-Up</button>
+        </div>
+    </div>
+
+    <button class="btn-primary btn-large full-width save-btn" @onclick="SaveInspection" disabled="@isSaving">
+        @(isSaving ? "Saving..." : "💾 Save Inspection")
+    </button>
+</div>
+
+@code {
+    [Parameter] public string? SiteId { get; set; }
+
+    private List<ConstructionSite> sites = new();
+    private string selectedSiteId = string.Empty;
+    private string selectedSiteName = string.Empty;
+    private string inspectorName = string.Empty;
+    private string generalNotes = string.Empty;
+    private InspectionStatus status = InspectionStatus.InProgress;
+    private List<ChecklistItem> checklist = new();
+    private HashSet<string> expandedNotes = new();
+    private List<PhotoRecord> photoRecords = new();
+    private List<(string id, string base64)> photoDataList = new();
+    private bool isSaving;
+
+    protected override async Task OnAfterRenderAsync(bool firstRender)
+    {
+        if (firstRender)
+        {
+            sites = await Db.GetAllSitesAsync();
+            checklist = ChecklistTemplates.GetSafetyChecklist();
+
+            if (!string.IsNullOrEmpty(SiteId))
+            {
+                selectedSiteId = SiteId;
+                var site = await Db.GetSiteAsync(SiteId);
+                selectedSiteName = site?.Name ?? "Unknown Site";
+            }
+
+            StateHasChanged();
+        }
+    }
+
+    private void ToggleResult(ChecklistItem item, CheckResult result)
+    {
+        item.Result = item.Result == result ? CheckResult.NotChecked : result;
+    }
+
+    private async Task HandlePhotoSelected(InputFileChangeEventArgs e)
+    {
+        foreach (var file in e.GetMultipleFiles(10))
+        {
+            try
+            {
+                var buffer = new byte[file.Size];
+                await file.OpenReadStream(maxAllowedSize: 10 * 1024 * 1024).ReadAsync(buffer);
+                var base64 = Convert.ToBase64String(buffer);
+                var id = Guid.NewGuid().ToString();
+                var record = new PhotoRecord
+                {
+                    Id = id,
+                    FileName = file.Name,
+                    TakenAt = DateTime.UtcNow,
+                    FileSizeBytes = file.Size
+                };
+                photoRecords.Add(record);
+                photoDataList.Add((id, base64));
+            }
+            catch { /* skip files that are too large */ }
+        }
+    }
+
+    private void RemovePhoto(PhotoRecord photo)
+    {
+        photoRecords.Remove(photo);
+        photoDataList.RemoveAll(p => p.id == photo.Id);
+    }
+
+    private async Task SaveInspection()
+    {
+        var siteId = !string.IsNullOrEmpty(SiteId) ? SiteId : selectedSiteId;
+        if (string.IsNullOrWhiteSpace(siteId) || string.IsNullOrWhiteSpace(inspectorName))
+            return;
+
+        isSaving = true;
+        StateHasChanged();
+
+        try
+        {
+            var site = await Db.GetSiteAsync(siteId);
+            var inspection = new Inspection
+            {
+                SiteId = siteId,
+                SiteName = site?.Name ?? "Unknown",
+                InspectorName = inspectorName,
+                Notes = generalNotes,
+                Status = status,
+                ChecklistItems = checklist,
+                Photos = photoRecords,
+                SyncState = SyncState.Pending
+            };
+
+            await Db.SaveInspectionAsync(inspection);
+
+            // Save photo blobs
+            foreach (var (id, base64) in photoDataList)
+            {
+                var record = photoRecords.First(p => p.Id == id);
+                await Db.SavePhotoAsync(inspection.Id, record.FileName, record.Caption, record.FileSizeBytes, base64);
+            }
+
+            Nav.NavigateTo($"/inspection/{inspection.Id}");
+        }
+        finally
+        {
+            isSaving = false;
+        }
+    }
+
+    private void GoBack() => Nav.NavigateTo("/");
+}
+

