kind.prompt:
Create the Blazor WASM pages and components for a construction site inspection PWA app.

Working directory: /tmp/sv-d2dd13e687734e22a73607d363aa276a/SiteInspector.Client

The app uses these services (already being created separately):
- `IndexedDbService` - CRUD for sites, inspections, photos via IndexedDB
- `SyncService` - syncs pending inspections to server

Models (in SiteInspector.Shared.Models):
- `ConstructionSite` { Id, Name, Address, Notes, CreatedAt }
- `Inspection` { Id, SiteId, SiteName, InspectorName, InspectedAt, Notes, Status (enum: InProgress/Completed/NeedsFollowUp), ChecklistItems, Photos, SyncState (enum: Pending/Synced/Failed), LastSyncedAt }
- `ChecklistItem` { Id, Category, Description, Result (enum: NotChecked/Pass/Fail/NotApplicable), Notes, SortOrder }
- `PhotoRecord` { Id, FileName, Caption, TakenAt, FileSizeBytes }
- `ChecklistTemplates.GetSafetyChecklist()` returns a default list of ChecklistItem

The app has these pages. Create each one:

### 1. Pages/Home.razor - Dashboard
Route: "/"

Shows:
- A header "Site Inspector" with a sync status indicator (colored dot: green=online+synced, yellow=syncing, red=offline or pending)
- Quick action buttons: "New Inspection" and "Manage Sites"
- "Recent Inspections" list showing last 10 inspections with site name, date, status badge, and sync state icon
- Pending sync count badge

Mobile-first design - large touch targets (min 48px), cards layout.

```razor
@page "/"
@using SiteInspector.Client.Services
@using SiteInspector.Shared.Models
@inject IndexedDbService Db
@inject NavigationManager Nav
@inject SyncService Sync

<div class="page-header">
    <h1>🏗️ Site Inspector</h1>
    <div class="sync-indicator @GetSyncClass()" @onclick="SyncNow">
        <span class="sync-dot"></span>
        <span class="sync-text">@GetSyncText()</span>
    </div>
</div>

<div class="action-buttons">
    <button class="btn-primary btn-large" @onclick='() => Nav.NavigateTo("/new-inspection")'>
        ➕ New Inspection
    </button>
    <button class="btn-secondary btn-large" @onclick='() => Nav.NavigateTo("/sites")'>
        📍 Manage Sites
    </button>
</div>

@if (pendingCount > 0)
{
    <div class="pending-banner" @onclick="SyncNow">
        🔄 @pendingCount inspection(s) pending sync — tap to sync now
    </div>
}

<h2>Recent Inspections</h2>
@if (recentInspections.Any())
{
    <div class="card-list">
        @foreach (var inspection in recentInspections)
        {
            <div class="card" @onclick="() => ViewInspection(inspection.Id)">
                <div class="card-header">
                    <strong>@inspection.SiteName</strong>
                    <span class="badge @GetStatusClass(inspection.Status)">@inspection.Status</span>
                </div>
                <div class="card-body">
                    <span>📅 @inspection.InspectedAt.ToString("MMM dd, yyyy h:mm tt")</span>
                    <span>👷 @inspection.InspectorName</span>
                </div>
                <div class="card-footer">
                    <span class="sync-badge @GetSyncStateClass(inspection.SyncState)">
                        @GetSyncIcon(inspection.SyncState) @inspection.SyncState
                    </span>
                    <span>@inspection.ChecklistItems.Count items</span>
                </div>
            </div>
        }
    </div>
}
else
{
    <div class="empty-state">
        <p>No inspections yet. Start your first inspection!</p>
    </div>
}

@code {
    private List<Inspection> recentInspections = new();
    private int pendingCount;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            await LoadData();
            Sync.OnSyncStatusChanged += _ => InvokeAsync(async () => { await LoadData(); StateHasChanged(); });
            StateHasChanged();
        }
    }

    private async Task LoadData()
    {
        var all = await Db.GetAllInspectionsAsync();
        recentInspections = all.OrderByDescending(i => i.InspectedAt).Take(10).ToList();
        pendingCount = all.Count(i => i.SyncState != SyncState.Synced);
    }

    private async Task SyncNow() => await Sync.TrySyncAsync();

    private void ViewInspection(string id) => Nav.NavigateTo($"/inspection/{id}");

    private string GetSyncClass() => Sync.CurrentStatus switch
    {
        { IsSyncing: true } => "syncing",
        { IsOnline: true } when pendingCount == 0 => "online",
        { IsOnline: true } => "pending",
        _ => "offline"
    };

    private string GetSyncText() => Sync.CurrentStatus switch
    {
        { IsSyncing: true } => "Syncing...",
        { IsOnline: true } when pendingCount == 0 => "Online",
        { IsOnline: true } => "Pending",
        _ => "Offline"
    };

    private string GetStatusClass(InspectionStatus status) => status switch
    {
        InspectionStatus.Completed => "badge-success",
        InspectionStatus.NeedsFollowUp => "badge-warning",
        _ => "badge-info"
    };

    private string GetSyncStateClass(SyncState state) => state switch
    {
        SyncState.Synced => "sync-ok",
        SyncState.Failed => "sync-fail",
        _ => "sync-pending"
    };

    private string GetSyncIcon(SyncState state) => state switch
    {
        SyncState.Synced => "☁️",
        SyncState.Failed => "⚠️",
        _ => "📱"
    };
}
```

### 2. Pages/Sites.razor - Site Management
Route: "/sites"

Shows list of construction sites with an "Add Site" form (inline). Each site has name, address, notes fields. Simple card list. Button to view inspection history for each site.

```razor
@page "/sites"
@using SiteInspector.Client.Services
@using SiteInspector.Shared.Models
@inject IndexedDbService Db
@inject NavigationManager Nav

<div class="page-header">
    <button class="btn-back" @onclick='() => Nav.NavigateTo("/")'>← Back</button>
    <h1>📍 Construction Sites</h1>
</div>

@if (showForm)
{
    <div class="card form-card">
        <h3>@(isEditing ? "Edit Site" : "Add New Site")</h3>
        <div class="form-group">
            <label>Site Name *</label>
            <input type="text" @bind="editSite.Name" placeholder="e.g. Riverside Tower" class="input-large" />
        </div>
        <div class="form-group">
            <label>Address *</label>
            <input type="text" @bind="editSite.Address" placeholder="123 Main St" class="input-large" />
        </div>
        <div class="form-group">
            <label>Notes</label>
            <textarea @bind="editSite.Notes" rows="3" placeholder="Optional notes..."></textarea>
        </div>
        <div class="form-actions">
            <button class="btn-primary" @onclick="SaveSite">💾 Save</button>
            <button class="btn-secondary" @onclick="CancelEdit">Cancel</button>
        </div>
    </div>
}
else
{
    <button class="btn-primary btn-large full-width" @onclick="ShowAddForm">➕ Add New Site</button>
}

<div class="card-list">
    @foreach (var site in sites)
    {
        <div class="card">
            <div class="card-header">
                <strong>@site.Name</strong>
            </div>
            <div class="card-body">
                <span>📍 @site.Address</span>
                @if (!string.IsNullOrEmpty(site.Notes))
                {
                    <span class="text-muted">@site.Notes</span>
                }
            </div>
            <div class="card-footer">
                <button class="btn-small btn-primary" @onclick="() => StartInspection(site)">🔍 Inspect</button>
                <button class="btn-small btn-secondary" @onclick="() => EditSite(site)">✏️</button>
                <button class="btn-small btn-danger" @onclick="() => DeleteSite(site)">🗑️</button>
            </div>
        </div>
    }
</div>

@if (!sites.Any() && !showForm)
{
    <div class="empty-state">
        <p>No sites added yet. Add your first construction site above.</p>
    </div>
}

@code {
    private List<ConstructionSite> sites = new();
    private ConstructionSite editSite = new();
    private bool showForm;
    private bool isEditing;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            sites = await Db.GetAllSitesAsync();
            StateHasChanged();
        }
    }

    private void ShowAddForm()
    {
        editSite = new ConstructionSite();
        isEditing = false;
        showForm = true;
    }

    private void EditSite(ConstructionSite site)
    {
        editSite = new ConstructionSite
        {
            Id = site.Id,
            Name = site.Name,
            Address = site.Address,
            Notes = site.Notes,
            CreatedAt = site.CreatedAt
        };
        isEditing = true;
        showForm = true;
    }

    private async Task SaveSite()
    {
        if (string.IsNullOrWhiteSpace(editSite.Name)) return;
        await Db.AddSiteAsync(editSite);
        sites = await Db.GetAllSitesAsync();
        showForm = false;
    }

    private void CancelEdit()
    {
        showForm = false;
    }

    private async Task DeleteSite(ConstructionSite site)
    {
        await Db.DeleteSiteAsync(site.Id);
        sites = await Db.GetAllSitesAsync();
    }

    private void StartInspection(ConstructionSite site)
    {
        Nav.NavigateTo($"/new-inspection/{site.Id}");
    }
}
```

### 3. Pages/NewInspection.razor - Create/conduct an inspection
Route: "/new-inspection" and "/new-inspection/{SiteId}"

This is the main page inspectors use in the field. It has:
- Site selector (if not pre-selected via route)
- Inspector name input
- The safety checklist grouped by category, with large tap targets for Pass/Fail/NA
- Notes field for each checklist item (expandable)
- Photo capture section
- General notes
- Status selector (InProgress, Completed, NeedsFollowUp)
- Save button

For the checklist, use a tap-through design: each item shows the description with three large buttons (✅ Pass, ❌ Fail, ➖ N/A). The currently selected result is highlighted. Tapping again on the same result deselects it (back to NotChecked).

Per-item notes: a small "Add note" link that expands a textarea below the item.

```razor
@page "/new-inspection"
@page "/new-inspection/{SiteId}"
@using SiteInspector.Client.Services
@using SiteInspector.Shared.Models
@inject IndexedDbService Db
@inject NavigationManager Nav
@inject IJSRuntime JS

<div class="page-header">
    <button class="btn-back" @onclick="GoBack">← Back</button>
    <h1>🔍 New Inspection</h1>
</div>

<div class="inspection-form">
    @if (string.IsNullOrEmpty(SiteId))
    {
        <div class="form-group">
            <label>Select Site *</label>
            <select @bind="selectedSiteId" class="input-large">
                <option value="">-- Choose a site --</option>
                @foreach (var site in sites)
                {
                    <option value="@site.Id">@site.Name — @site.Address</option>
                }
            </select>
        </div>
    }
    else
    {
        <div class="site-banner">📍 @selectedSiteName</div>
    }

    <div class="form-group">
        <label>Inspector Name *</label>
        <input type="text" @bind="inspectorName" placeholder="Your name" class="input-large" />
    </div>

    <h2>Safety Checklist</h2>
    @{
        string? currentCategory = null;
    }
    @foreach (var item in checklist)
    {
        if (item.Category != currentCategory)
        {
            currentCategory = item.Category;
            <h3 class="category-header">@currentCategory</h3>
        }
        <div class="checklist-item @(item.Result != CheckResult.NotChecked ? "checked" : "")">
            <div class="checklist-description">@item.Description</div>
            <div class="checklist-buttons">
                <button class="check-btn pass @(item.Result == CheckResult.Pass ? "active" : "")"
                        @onclick="() => ToggleResult(item, CheckResult.Pass)">✅</button>
                <button class="check-btn fail @(item.Result == CheckResult.Fail ? "active" : "")"
                        @onclick="() => ToggleResult(item, CheckResult.Fail)">❌</button>
                <button class="check-btn na @(item.Result == CheckResult.NotApplicable ? "active" : "")"
                        @onclick="() => ToggleResult(item, CheckResult.NotApplicable)">➖</button>
            </div>
            @if (expandedNotes.Contains(item.Id))
            {
                <textarea class="item-notes" @bind="item.Notes" placeholder="Add notes for this item..." rows="2"></textarea>
            }
            else
            {
                <button class="btn-link" @onclick="() => expandedNotes.Add(item.Id)">
                    @(string.IsNullOrEmpty(item.Notes) ? "📝 Add note" : $"📝 {item.Notes[..Math.Min(item.Notes.Length, 30)]}...")
                </button>
            }
        </div>
    }

    <h2>📸 Photos</h2>
    <div class="photo-section">
        <label class="photo-capture-btn">
            📷 Take Photo / Choose File
            <InputFile OnChange="HandlePhotoSelected" accept="image/*" capture="environment" multiple class="hidden-input" />
        </label>
        @if (photoRecords.Any())
        {
            <div class="photo-grid">
                @foreach (var photo in photoRecords)
                {
                    <div class="photo-thumb">
                        <div class="photo-name">@photo.FileName</div>
                        <button class="btn-small btn-danger" @onclick="() => RemovePhoto(photo)">🗑️</button>
                    </div>
                }
            </div>
        }
    </div>

    <div class="form-group">
        <label>General Notes</label>
        <textarea @bind="generalNotes" rows="4" placeholder="Overall observations, concerns, follow-up items..." class="input-large"></textarea>
    </div>

    <div class="form-group">
        <label>Status</label>
        <div class="status-buttons">
            <button class="status-btn @(status == InspectionStatus.InProgress ? "active" : "")"
                    @onclick="() => status = InspectionStatus.InProgress">🔄 In Progress</button>
            <button class="status-btn @(status == InspectionStatus.Completed ? "active" : "")"
                    @onclick="() => status = InspectionStatus.Completed">✅ Completed</button>
            <button class="status-btn @(status == InspectionStatus.NeedsFollowUp ? "active" : "")"
                    @onclick="() => status = InspectionStatus.NeedsFollowUp">⚠️ Needs Follow-Up</button>
        </div>
    </div>

    <button class="btn-primary btn-large full-width save-btn" @onclick="SaveInspection" disabled="@isSaving">
        @(isSaving ? "Saving..." : "💾 Save Inspection")
    </button>
</div>

@code {
    [Parameter] public string? SiteId { get; set; }

    private List<ConstructionSite> sites = new();
    private string selectedSiteId = string.Empty;
    private string selectedSiteName = string.Empty;
    private string inspectorName = string.Empty;
    private string generalNotes = string.Empty;
    private InspectionStatus status = InspectionStatus.InProgress;
    private List<ChecklistItem> checklist = new();
    private HashSet<string> expandedNotes = new();
    private List<PhotoRecord> photoRecords = new();
    private List<(string id, string base64)> photoDataList = new();
    private bool isSaving;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            sites = await Db.GetAllSitesAsync();
            checklist = ChecklistTemplates.GetSafetyChecklist();

            if (!string.IsNullOrEmpty(SiteId))
            {
                selectedSiteId = SiteId;
                var site = await Db.GetSiteAsync(SiteId);
                selectedSiteName = site?.Name ?? "Unknown Site";
            }

            StateHasChanged();
        }
    }

    private void ToggleResult(ChecklistItem item, CheckResult result)
    {
        item.Result = item.Result == result ? CheckResult.NotChecked : result;
    }

    private async Task HandlePhotoSelected(InputFileChangeEventArgs e)
    {
        foreach (var file in e.GetMultipleFiles(10))
        {
            try
            {
                var buffer = new byte[file.Size];
                await file.OpenReadStream(maxAllowedSize: 10 * 1024 * 1024).ReadAsync(buffer);
                var base64 = Convert.ToBase64String(buffer);
                var id = Guid.NewGuid().ToString();
                var record = new PhotoRecord
                {
                    Id = id,
                    FileName = file.Name,
                    TakenAt = DateTime.UtcNow,
                    FileSizeBytes = file.Size
                };
                photoRecords.Add(record);
                photoDataList.Add((id, base64));
            }
            catch { /* skip files that are too large */ }
        }
    }

    private void RemovePhoto(PhotoRecord photo)
    {
        photoRecords.Remove(photo);
        photoDataList.RemoveAll(p => p.id == photo.Id);
    }

    private async Task SaveInspection()
    {
        var siteId = !string.IsNullOrEmpty(SiteId) ? SiteId : selectedSiteId;
        if (string.IsNullOrWhiteSpace(siteId) || string.IsNullOrWhiteSpace(inspectorName))
            return;

        isSaving = true;
        StateHasChanged();

        try
        {
            var site = await Db.GetSiteAsync(siteId);
            var inspection = new Inspection
            {
                SiteId = siteId,
                SiteName = site?.Name ?? "Unknown",
                InspectorName = inspectorName,
                Notes = generalNotes,
                Status = status,
                ChecklistItems = checklist,
                Photos = photoRecords,
                SyncState = SyncState.Pending
            };

            await Db.SaveInspectionAsync(inspection);

            // Save photo blobs
            foreach (var (id, base64) in photoDataList)
            {
                var record = photoRecords.First(p => p.Id == id);
                await Db.SavePhotoAsync(inspection.Id, record.FileName, record.Caption, record.FileSizeBytes, base64);
            }

            Nav.NavigateTo($"/inspection/{inspection.Id}");
        }
        finally
        {
            isSaving = false;
        }
    }

    private void GoBack() => Nav.NavigateTo("/");
}
```

### 4. Pages/InspectionDetail.razor - View a completed inspection
Route: "/inspection/{Id}"

Shows the full inspection report: site info, inspector, date, status, checklist results (color-coded), photos (thumbnails that expand), notes, sync status.

```razor
@page "/inspection/{Id}"
@using SiteInspector.Client.Services
@using SiteInspector.Shared.Models
@inject IndexedDbService Db
@inject NavigationManager Nav
@inject SyncService Sync

<div class="page-header">
    <button class="btn-back" @onclick='() => Nav.NavigateTo("/")'>← Back</button>
    <h1>📋 Inspection Report</h1>
</div>

@if (inspection is not null)
{
    <div class="report-header card">
        <div class="report-site">📍 @inspection.SiteName</div>
        <div class="report-meta">
            <span>👷 @inspection.InspectorName</span>
            <span>📅 @inspection.InspectedAt.ToString("MMM dd, yyyy h:mm tt")</span>
        </div>
        <div class="report-status">
            <span class="badge @GetStatusClass(inspection.Status)">@inspection.Status</span>
            <span class="sync-badge @GetSyncClass(inspection.SyncState)">
                @GetSyncIcon(inspection.SyncState) @inspection.SyncState
            </span>
        </div>
    </div>

    @if (!string.IsNullOrEmpty(inspection.Notes))
    {
        <div class="card">
            <h3>📝 Notes</h3>
            <p>@inspection.Notes</p>
        </div>
    }

    <div class="card">
        <h3>✅ Checklist Results</h3>
        <div class="results-summary">
            <span class="result-count pass">✅ @inspection.ChecklistItems.Count(i => i.Result == CheckResult.Pass) Pass</span>
            <span class="result-count fail">❌ @inspection.ChecklistItems.Count(i => i.Result == CheckResult.Fail) Fail</span>
            <span class="result-count na">➖ @inspection.ChecklistItems.Count(i => i.Result == CheckResult.NotApplicable) N/A</span>
            <span class="result-count unchecked">⬜ @inspection.ChecklistItems.Count(i => i.Result == CheckResult.NotChecked) Unchecked</span>
        </div>

        @{
            string? currentCategory = null;
        }
        @foreach (var item in inspection.ChecklistItems.OrderBy(i => i.SortOrder))
        {
            if (item.Category != currentCategory)
            {
                currentCategory = item.Category;
                <h4 class="category-header">@currentCategory</h4>
            }
            <div class="result-item @GetResultClass(item.Result)">
                <span class="result-icon">@GetResultIcon(item.Result)</span>
                <span class="result-desc">@item.Description</span>
                @if (!string.IsNullOrEmpty(item.Notes))
                {
                    <div class="result-notes">📝 @item.Notes</div>
                }
            </div>
        }
    </div>

    @if (photos.Any())
    {
        <div class="card">
            <h3>📸 Photos (@photos.Count)</h3>
            <div class="photo-grid">
                @foreach (var photo in photos)
                {
                    <div class="photo-card" @onclick="() => TogglePhotoExpand(photo.Id)">
                        @if (expandedPhotos.Contains(photo.Id) && loadedPhotos.ContainsKey(photo.Id))
                        {
                            <img src="data:image/jpeg;base64,@loadedPhotos[photo.Id]" alt="@photo.FileName" class="photo-full" />
                        }
                        else
                        {
                            <div class="photo-placeholder">📷</div>
                        }
                        <div class="photo-info">
                            <span>@photo.FileName</span>
                            @if (!string.IsNullOrEmpty(photo.Caption))
                            {
                                <span class="text-muted">@photo.Caption</span>
                            }
                        </div>
                    </div>
                }
            </div>
        </div>
    }

    @if (inspection.SyncState != SyncState.Synced)
    {
        <button class="btn-primary btn-large full-width" @onclick="TrySync">
            🔄 Sync Now
        </button>
    }
}
else if (loaded)
{
    <div class="empty-state">
        <p>Inspection not found.</p>
    </div>
}

@code {
    [Parameter] public string Id { get; set; } = string.Empty;

    private Inspection? inspection;
    private List<PhotoRecord> photos = new();
    private HashSet<string> expandedPhotos = new();
    private Dictionary<string, string> loadedPhotos = new();
    private bool loaded;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            inspection = await Db.GetInspectionAsync(Id);
            if (inspection is not null)
            {
                photos = await Db.GetPhotosByInspectionAsync(Id);
            }
            loaded = true;
            StateHasChanged();
        }
    }

    private async Task TogglePhotoExpand(string photoId)
    {
        if (expandedPhotos.Contains(photoId))
        {
            expandedPhotos.Remove(photoId);
        }
        else
        {
            expandedPhotos.Add(photoId);
            if (!loadedPhotos.ContainsKey(photoId))
            {
                var data = await Db.GetPhotoDataAsync(photoId);
                if (data is not null)
                    loadedPhotos[photoId] = data;
            }
        }
    }

    private async Task TrySync() => await Sync.TrySyncAsync();

    private string GetStatusClass(InspectionStatus s) => s switch
    {
        InspectionStatus.Completed => "badge-success",
        InspectionStatus.NeedsFollowUp => "badge-warning",
        _ => "badge-info"
    };

    private string GetSyncClass(SyncState s) => s switch
    {
        SyncState.Synced => "sync-ok",
        SyncState.Failed => "sync-fail",
        _ => "sync-pending"
    };

    private string GetSyncIcon(SyncState s) => s switch
    {
        SyncState.Synced => "☁️",
        SyncState.Failed => "⚠️",
        _ => "📱"
    };

    private string GetResultClass(CheckResult r) => r switch
    {
        CheckResult.Pass => "result-pass",
        CheckResult.Fail => "result-fail",
        CheckResult.NotApplicable => "result-na",
        _ => "result-unchecked"
    };

    private string GetResultIcon(CheckResult r) => r switch
    {
        CheckResult.Pass => "✅",
        CheckResult.Fail => "❌",
        CheckResult.NotApplicable => "➖",
        _ => "⬜"
    };
}
