    min-height: 56px;
}

.photo-capture-btn:active { background: var(--bg); }

.hidden-input { display: none; }

.photo-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(140px, 1fr));
    gap: 0.5rem;
    margin-top: 0.75rem;
}

.photo-thumb, .photo-card {
    background: var(--surface);
    border: 1px solid var(--border);
    border-radius: 8px;
    padding: 0.5rem;
    text-align: center;
}

.photo-name {
    font-size: 0.8rem;
    color: var(--text-muted);
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
    margin-bottom: 0.25rem;
}

.photo-placeholder {
    font-size: 2rem;
    padding: 1rem;
    background: var(--bg);
    border-radius: 8px;
    margin-bottom: 0.5rem;
}

.photo-full {
    width: 100%;
    border-radius: 8px;
    margin-bottom: 0.5rem;
}

.photo-info {
    font-size: 0.8rem;
    display: flex;
    flex-direction: column;
}

/* === Status Buttons === */
.status-buttons {
    display: flex;
    gap: 0.5rem;
    flex-wrap: wrap;
}

.status-btn {
    flex: 1;
    min-width: 120px;
    padding: 0.75rem 0.5rem;
    border-radius: var(--radius);
    font-size: 0.9rem;
    font-weight: 600;
    background: var(--surface);
    border: 2px solid var(--border);
    min-height: 48px;
    transition: all 0.15s;
}

.status-btn.active {
    border-color: var(--primary);
    background: #e0f2fe;
    color: var(--primary);
}

/* === Save Button === */
.save-btn { margin-top: 1.5rem; margin-bottom: 2rem; }

/* === Inspection Detail / Report === */
.report-header { text-align: center; }

.report-site {
    font-size: 1.2rem;
    font-weight: 700;
    margin-bottom: 0.5rem;
}

.report-meta {
    display: flex;
    flex-direction: column;
    gap: 0.25rem;
    font-size: 0.9rem;
    color: var(--text-muted);
    margin-bottom: 0.5rem;
}

.report-status {
    display: flex;
    justify-content: center;
    gap: 0.75rem;
    align-items: center;
}

.results-summary {
    display: flex;
    flex-wrap: wrap;
    gap: 0.5rem;
    margin-bottom: 1rem;
}

.result-count {
    padding: 0.35rem 0.75rem;
    border-radius: 20px;
    font-size: 0.85rem;
    font-weight: 600;
}

.result-count.pass { background: #dcfce7; color: #166534; }
.result-count.fail { background: #fef2f2; color: #991b1b; }
.result-count.na { background: #f1f5f9; color: #475569; }
.result-count.unchecked { background: #f8fafc; color: #94a3b8; }

.result-item {
    display: flex;
    align-items: flex-start;
    gap: 0.5rem;
    padding: 0.5rem 0;
    border-bottom: 1px solid var(--border);
    flex-wrap: wrap;
}

.result-icon { font-size: 1.1rem; flex-shrink: 0; }

.result-desc { flex: 1; font-size: 0.9rem; }

.result-notes {
    width: 100%;
    font-size: 0.8rem;
    color: var(--text-muted);
    padding-left: 1.6rem;
}

.result-pass { }
.result-fail { background: #fef2f2; border-radius: 8px; padding: 0.5rem; }
.result-na { opacity: 0.6; }
.result-unchecked { opacity: 0.4; }

/* === Empty State === */
.empty-state {
    text-align: center;
    padding: 3rem 1rem;
    color: var(--text-muted);
}

.text-muted { color: var(--text-muted); }

/* === Loading === */
.loading-progress {
    position: absolute;
    display: block;
    width: 8rem;
    height: 8rem;
    inset: 20vh 0 auto 0;
    margin: 0 auto;
}

.loading-progress circle {
    fill: none;
    stroke: #e0e0e0;
    stroke-width: 0.6rem;
    transform-origin: 50% 50%;
    transform: rotate(-90deg);
}

.loading-progress circle:last-child {
    stroke: var(--primary);
    stroke-dasharray: calc(3.141 * var(--blazor-load-percentage, 0%) * 0.8), 500%;
    transition: stroke-dasharray 0.05s ease-in-out;
}

.loading-progress-text {
    position: absolute;
    text-align: center;
    font-weight: bold;
    inset: calc(20vh + 3.25rem) 0 auto 0.2rem;
}

.loading-progress-text:after {
    content: var(--blazor-load-percentage-text, "Loading");
}

/* === Error UI === */
#blazor-error-ui {
    background: lightyellow;
    bottom: 0;
    box-shadow: 0 -1px 2px rgba(0,0,0,0.2);
    display: none;
    left: 0;
    padding: 0.6rem 1.25rem;
    position: fixed;
    width: 100%;
    z-index: 1000;
}

#blazor-error-ui .dismiss {
    cursor: pointer;
    position: absolute;
    right: 0.75rem;
    top: 0.5rem;
}

.blazor-error-boundary {
    background: #b32121;
    padding: 1rem;
    color: white;
    border-radius: var(--radius);
}

.blazor-error-boundary::after { content: "An error has occurred."; }

