using Microsoft.EntityFrameworkCore;
using SiteInspector.Shared.Models;

namespace SiteInspector.Server.Data;

public class AppDbContext : DbContext
{
    public AppDbContext(DbContextOptions<AppDbContext> options) : base(options) { }

    public DbSet<ConstructionSite> Sites => Set<ConstructionSite>();
    public DbSet<InspectionEntity> Inspections => Set<InspectionEntity>();

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<ConstructionSite>().HasKey(s => s.Id);

        modelBuilder.Entity<InspectionEntity>(e =>
        {
            e.HasKey(i => i.Id);
            e.Property(i => i.ChecklistItemsJson).HasColumnName("ChecklistItems");
            e.Property(i => i.PhotosJson).HasColumnName("Photos");
        });
    }
}

/// <summary>
/// Flattened entity for storing inspections in SQLite.
/// Checklist items and photos are serialized as JSON columns.
/// </summary>
public class InspectionEntity
{
    public string Id { get; set; } = string.Empty;
    public string SiteId { get; set; } = string.Empty;
    public string SiteName { get; set; } = string.Empty;
    public string InspectorName { get; set; } = string.Empty;
    public DateTime InspectedAt { get; set; }
    public string? Notes { get; set; }
    public int Status { get; set; }
    public string ChecklistItemsJson { get; set; } = "[]";
    public string PhotosJson { get; set; } = "[]";
    public DateTime ReceivedAt { get; set; } = DateTime.UtcNow;
}

