using Microsoft.EntityFrameworkCore;
using SiteInspector.Server.Data;
using SiteInspector.Shared.Models;
using System.Text.Json;

var builder = WebApplication.CreateBuilder(args);

builder.Services.AddDbContext<AppDbContext>(opt =>
    opt.UseSqlite("Data Source=siteinspector.db"));

builder.Services.AddCors(options =>
    options.AddDefaultPolicy(policy =>
        policy.AllowAnyOrigin().AllowAnyMethod().AllowAnyHeader()));

var app = builder.Build();

using (var scope = app.Services.CreateScope())
{
    var db = scope.ServiceProvider.GetRequiredService<AppDbContext>();
    db.Database.EnsureCreated();
}

app.UseCors();

// Receive synced inspections from the client
app.MapPost("/api/inspections", async (Inspection inspection, AppDbContext db) =>
{
    var entity = new InspectionEntity
    {
        Id = inspection.Id,
        SiteId = inspection.SiteId,
        SiteName = inspection.SiteName,
        InspectorName = inspection.InspectorName,
        InspectedAt = inspection.InspectedAt,
        Notes = inspection.Notes,
        Status = (int)inspection.Status,
        ChecklistItemsJson = JsonSerializer.Serialize(inspection.ChecklistItems),
        PhotosJson = JsonSerializer.Serialize(inspection.Photos),
        ReceivedAt = DateTime.UtcNow
    };

    var existing = await db.Inspections.FindAsync(entity.Id);
    if (existing is not null)
    {
        db.Entry(existing).CurrentValues.SetValues(entity);
    }
    else
    {
        db.Inspections.Add(entity);
    }

    // Upsert the site
    if (!await db.Sites.AnyAsync(s => s.Id == inspection.SiteId))
    {
        db.Sites.Add(new ConstructionSite
        {
            Id = inspection.SiteId,
            Name = inspection.SiteName
        });
    }

    await db.SaveChangesAsync();
    return Results.Ok(new { synced = true, id = inspection.Id });
});

// Get all inspections (for admin/reporting)
app.MapGet("/api/inspections", async (AppDbContext db) =>
{
    var inspections = await db.Inspections
        .OrderByDescending(i => i.InspectedAt)
        .ToListAsync();
    return Results.Ok(inspections);
});

// Get inspection by ID
app.MapGet("/api/inspections/{id}", async (string id, AppDbContext db) =>
{
    var entity = await db.Inspections.FindAsync(id);
    return entity is not null ? Results.Ok(entity) : Results.NotFound();
});

// Health check for connectivity detection
app.MapGet("/api/health", () => Results.Ok(new { status = "ok", timestamp = DateTime.UtcNow }));

app.Run();

